import React, { FunctionComponent } from "react";
import { ctx } from "../services/Context";
import { observer } from "mobx-react";
import { OurToaster } from "./OurToaster";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";
import { Pending } from "./Pending";
import { Client } from "./Client";
import { Banker } from "./Banker";
import {
  Alignment,
  Button,
  Classes,
  Navbar,
  NavbarDivider,
  NavbarGroup,
  NavbarHeading
} from "@blueprintjs/core";

export const Connected: FunctionComponent = observer(() => {
  const menu: any =
    ctx.store.getRole() === "client" ? (
      <Client />
    ) : ctx.store.getRole() === "banker" ? (
      <Banker />
    ) : (
      <Pending />
    );

  function username(): string {
    return `Signed in as ${ctx.store.getName()}`;
  }

  function home(): any {
    if (ctx.store.getRole() !== "pending")
      return <Button className={Classes.MINIMAL} icon="home" text="Home" />;
  }

  function logout(): void {
    ctx.store.setName("");
    ctx.store.setRole("");
    OurToaster.show({
      message: "Successfully disconnected.",
      intent: Intent.SUCCESS,
      timeout: 8000
    });
  }
  return (
    <div>
      <Navbar className="outline-style-d">
        <NavbarGroup align={Alignment.LEFT}>
          <NavbarHeading className="title-primary">Heabank</NavbarHeading>
          <NavbarDivider />
          <NavbarHeading className="title-primary">{username()}</NavbarHeading>
          <NavbarDivider />
          {home()}
        </NavbarGroup>
        <NavbarGroup align={Alignment.RIGHT}>
          <NavbarDivider />
          <Button
            className={Classes.MINIMAL}
            onClick={() => logout()}
            icon="log-out"
            text="Log-out"
          />
        </NavbarGroup>
      </Navbar>
      {menu}
    </div>
  );
});

